/**
 * Noticias diarias del Mundial 2026.
 *
 * Curaduría editorial: cada noticia debe llevar título original del medio
 * + resumen propio (NO copiar el lead del medio · copyright) + URL.
 *
 * Cómo añadir una nueva:
 *   1. Encuentra la noticia en un medio relevante (Marca, AS, ESPN, FIFA,
 *      L'Équipe, The Guardian, BBC, OneFootball, Infobae, TyC Sports, etc.).
 *   2. Verifica fecha de publicación.
 *   3. Escribe un resumen propio en español (40-60 palabras), no traducir
 *      literalmente la entradilla del medio. Aporta contexto tuyo.
 *   4. Añade entrada al array `NEWS_ITEMS` con `publishedAt` ISO 8601.
 *   5. Reordena: las más recientes primero.
 *
 * Frecuencia ideal: 3-5 noticias nuevas por semana.
 *
 * Cuando esto crezca a >100 noticias, migrar a tabla Supabase
 * (migration en `supabase/migrations/20260502000000_news_items.sql`).
 */

export type NewsCategory =
  | 'panini'
  | 'convocatorias'
  | 'sedes'
  | 'entradas'
  | 'jugadores'
  | 'mascotas'
  | 'ceremonia'
  | 'polemica'
  | 'tv'
  | 'patrocinios'
  | 'amistosos'
  | 'lesiones'
  | 'tecnico'
  | 'general'
  | 'historica'
  | 'curiosa';

export type NewsItem = {
 /** Slug interno · usado en `/noticias/[slug]`. */
 slug: string;
 /** Título editorial propio (NO copiar textual del medio). */
 title: string;
 /** Resumen editorial propio en español, 40-60 palabras. */
 summary: string;
 /**
 * Cuerpo editorial propio en español (200-400 palabras), separado por
 * `\n\n` entre párrafos. NO traducción literal del medio. Aporta
 * contexto, datos verificados y opinión sutil.
 */
 body: string;
 /** Categoría para filtrado. */
 category: NewsCategory;
 /** Nombre del medio fuente. */
 sourceName: string;
 /** URL del artículo original (atribución obligatoria). */
 sourceUrl: string;
 /** Idioma del medio (no del resumen, que es ES). */
 sourceLang: 'es' | 'en' | 'pt' | 'fr';
 /** Fechas de publicación / actualización (ISO 8601). */
 publishedAt: string;
 modifiedAt?: string;
 /**
  * Autor de la pieza (byline). Si es un nombre de persona se emite como
  * `Person` en el schema (mejor E-E-A-T); si se omite, se usa la redacción.
  */
 author?: string;
 /** Fuentes secundarias (atribución adicional, para verificación cruzada). */
 sourcesSecondary?: { name: string; url: string }[];
 /**
 * Imagen de portada (1200×675 ideal Discover-friendly).
 * Recomendado: Wikimedia Commons via `Special:FilePath` con licencia libre.
 * Si se omite, se usa el OG dinámico de marca como fallback.
 */
 image?: {
 url: string;
 alt: string;
 credit?: string;
 license?: string;
 };
 /**
  * ID de YouTube del video destacado de la noticia (sin URL completa,
  * solo el ID, ej. '982yoXq6Mgk'). Si está presente, la página de la
  * noticia renderiza un iframe del video justo antes del body, y la
  * VideoObject schema queda asociada a la pieza.
  */
 youtubeVideoId?: string;
 /**
  * Traducciones del contenido editorial. La página `/[locale]/noticias/[slug]`
  * usa `i18n[locale]` si existe; si no, cae al español de `title`/`summary`/`body`.
  * Solo es necesario rellenar los locales en los que queremos publicar
  * versión traducida (la mayoría se quedan en español por ahora).
  */
 i18n?: Partial<Record<'en' | 'fr' | 'pt' | 'ar', {
   title: string;
   summary: string;
   body: string;
 }>>;
};

/**
 * Devuelve título, resumen y cuerpo en el locale solicitado. Cae a ES si
 * no hay traducción para ese locale. Útil para componentes y páginas.
 */
export function getLocalizedNews(
  item: NewsItem,
  locale: string,
): { title: string; summary: string; body: string } {
  const localeKey = locale as 'en' | 'fr' | 'pt' | 'ar';
  const t = item.i18n?.[localeKey];
  if (t) return { title: t.title, summary: t.summary, body: t.body };
  return { title: item.title, summary: item.summary, body: item.body };
}

/**
 * URL de imagen de una noticia, SIEMPRE con valor. Si la noticia no tiene
 * foto propia (p. ej. piezas de horarios/listas), cae a la tarjeta de marca
 * generada (el OG dinámico 1200×675 de la propia noticia). Así ninguna
 * noticia se publica sin imagen.
 */
export function newsImageUrl(item: NewsItem): string {
  return item.image?.url ?? `/noticias/${item.slug}/opengraph-image`;
}

/** Texto alternativo de la imagen de una noticia (cae al título). */
export function newsImageAlt(item: NewsItem): string {
  return item.image?.alt ?? item.title;
}

