    sourceName: 'SBS News / BBC News',
    sourceUrl: 'https://www.sbs.com.au/news/article/fifa-tech-heavy-world-cup-chargeable-ball-ai-avatars/p9anynqpc',
    sourceLang: 'en',
    publishedAt: '2026-06-05T16:00:00Z',
    image: {
      url: 'https://upload.wikimedia.org/wikipedia/commons/c/cf/FIFA_World_Cup_2026_Trionda_ball.jpg',
      alt: 'Balón oficial Adidas Trionda del Mundial 2026 con chip de IA integrado',
      credit: 'Wikimedia Commons',
      license: 'CC BY-SA 4.0',
    },
