    sourceUrl: 'https://www.beinsports.com/en-us/soccer/fifa-world-cup-2026/articles/the-german-mathematician-who-predicted-the-last-three-world-cup-champions-germany-france-and-argentina-2026-06-03',
    sourceLang: 'en',
